member.summary:
Static helpers shared by all built-in SDK actions.
Provides safe argument parsing and faction access so individual actions
stay short and focus on their own logic.

Usage pattern for a new IModTextAction:

public bool Execute(string[] args, GameCommandsReadyEvent? ctx)
{
    if (!ActionContextHelper.TryGetFloat(args, 0, out float amount, _log, CommandName))
        return false;
    if (!ActionContextHelper.TryGetFaction(ctx, out var faction, _log, CommandName))
        return false;

    faction.AddResearchPoints(amount);
    return true;
}

example.code:
if (!ActionContextHelper.TryGetFaction(ctx, out var faction, _log, CommandName))
    return false;
faction.AddResearchPoints(500f);

public class SpawnMyUnit : IModTextAction
{
    public string CommandName => "SpawnMyUnit";

    public bool Execute(string[] args, GameCommandsReadyEvent ctx)
    {
        string unitId = args.Length > 0 ? args[0] : "default_unit";
        // use ctx.NativeUniverse, ctx.NativePlayerFaction, etc.
        Log.LogInfo($"Spawning unit {unitId}");
        return true;
    }
}

// In plugin Load():
ModTextActionRegistry.Register<SpawnMyUnit>();

// In YAML:
actions:
  - command: SpawnMyUnit
    arguments:
      - my_unit_id

// Register by type (instance created automatically):
ModTextActionRegistry.Register<SpawnMyUnit>();

// Register an existing instance:
ModTextActionRegistry.Register(new SpawnMyUnit());

// Check registration:
bool ok = ModTextActionRegistry.IsRegistered("SpawnMyUnit");

// List all actions:
foreach (var name in ModTextActionRegistry.RegisteredActions)
    Log.LogInfo(name);

// Start dialogue between player faction and scientist
var result = new StartDialogueCommand(playerFaction, scientist, DialogueType.Research).Execute();

// Using convenience method
var result = Commands.StartDialogue(playerFaction, scientist, DialogueType.Research);

// Chain dialogues in a faction builder
Commands.ForFaction(playerFaction)
    .StartDialogue(scientist, DialogueType.Introduction)
    .StartDialogue(engineer, DialogueType.ProjectUpdate)
    .Execute();

// Lock sector 3 (e.g. satellite compromised)
Commands.ForFaction(playerFaction).LockSector(3).Execute();

// YAML (requires SDK plugin active):
// actions:
//   - command: LockSector
//     arguments:
//       - PlayerFaction
//       - 3

// Re-unlock after recovery:
// actions:
//   - command: UnlockSector
//     arguments:
//       - PlayerFaction
//       - 3

// Unlock sector 3 for player faction
Commands.ForFaction(playerFaction).UnlockSector(3).Execute();

// YAML equivalent:
// actions:
//   - command: UnlockSector
//     arguments:
//       - PlayerFaction
//       - 3

// Research advanced engineering for player faction
var result = new ResearchTechnologyCommand(playerFaction, TechnologyType.AdvancedEngineering).Execute();

// Using convenience method
var result = Commands.ResearchTechnology(playerFaction, TechnologyType.AdvancedEngineering);

// Chain multiple technology research
Commands.ForFaction(playerFaction)
    .ResearchTechnology(TechnologyType.BasicEngineering)
    .ResearchTechnology(TechnologyType.AdvancedEngineering)
    .ResearchTechnology(TechnologyType.ExpertEngineering)
    .Execute();

// Unlock basic chemistry knowledge for player faction
var result = new UnlockKnowledgeCommand(playerFaction, KnowledgeType.BasicChemistry).Execute();

// Using convenience method
var result = Commands.UnlockKnowledge(playerFaction, KnowledgeType.BasicChemistry);

// Unlock multiple knowledge items in sequence
Commands.ForFaction(playerFaction)
    .UnlockKnowledge(KnowledgeType.BasicPhysics)
    .UnlockKnowledge(KnowledgeType.BasicChemistry)
    .UnlockKnowledge(KnowledgeType.BasicBiology)
    .Execute();

// Lock advanced physics knowledge from AI faction
var result = new LockKnowledgeCommand(aiFaction, KnowledgeType.AdvancedPhysics).Execute();

// Lock multiple knowledge items for a faction
Commands.ForFaction(restrictedFaction)
    .LockKnowledge(KnowledgeType.NuclearPhysics)
    .LockKnowledge(KnowledgeType.QuantumMechanics)
    .Execute();

var actions = YamlCommandsParser.ParseFile("startup-actions.yaml");
int executed = YamlCommandsExecutor.ExecuteActions(actions);
Log.Info($"Executed {executed} / {actions.Count} actions");

// Parse from raw YAML string
var actions = YamlCommandsParser.ParseString(@"
  - command: FinishConstructions
    arguments: []
    daysDelay: 0.0
    showInFrontend: false
");

// Parse from a dedicated actions file
var actions = YamlCommandsParser.ParseFile(@"C:\mods\my-mod\startup-actions.yaml");

member.summary:
Registre statique des entités terrestres déclarées par les mods.
Le SDK lui-même ne livre aucune entité — c'est une responsabilité des mods consommateurs.


Cycle de vie typique :

// Dans le plugin BepInEx du mod :
EarthEntityRegistry.Register(new HeliosCorp());
EarthEntityRegistry.Register(new EsaCountry());
// ...
EarthEntityRegistry.OnRegistered += entity => LogAspera.Info($"Entity: {entity.Id}");

member.example:
public class HeliosCorp : EarthEntity
{
    public HeliosCorp() : base("corp_helios", "Helios Corp", EarthEntityType.Corporation) { }
    public override float GetOfferedPrice(string resourceKey) => resourceKey == "resource_iron" ? 1.5f : 1.0f;
}

// Crédit après export
orbitalStock.Credit("resource_iron", 500f, "mission_arean_survey");

// Débit pour livraison
if (!orbitalStock.TryDebit("resource_iron", 100f, "trade_offer_abc"))
    return TradeResult.Fail("Stock orbital insuffisant");

// Abonnement aux changements
orbitalStock.OnChanged += (key, delta, total) =>
    LogAspera.Info($"Orbital [{key}] Δ{delta:+0.#;-0.#} → {total}");

var offer = new TradeOffer
{
    Id             = Guid.NewGuid().ToString(),
    EntityId       = "corp_helios",
    ResourceKey    = "resource_iron",
    Quantity       = 500f,
    PricePerUnit   = 1.5f,
    Direction      = TradeDirection.MarsToEarth,
    ExpiresOnSol   = currentSol + 10,
    ReputationDelta = 5f,
};
tradeService.PostOffer(offer);

member.summary:
            Service de gestion des relations diplomatiques avec les entités terrestres.

Fonctions :


Appliquer des deltas de réputation + émettre .

Déclencher des incidents () sur changement de palier.

Miroir du score de réputation dans le blackboard principal du jeu
              (main.rep_{entityId}) pour que les règles YAML natives déclenchent quêtes/embargos.


            var diplomacy = new DiplomacyService();
            diplomacy.ApplyReputationDelta("corp_helios", +10f, "trade_completed", currentSol);
            diplomacy.RegisterIncidentTrigger("embargo_helios", "corp_helios", ReputationTier.Hostile);
            diplomacy.MirrorToBlackboard("corp_helios");  // main.rep_corp_helios = valeur

            Service SDK qui maintient le stock orbital à partir des projets spatiaux complétés.

Principe :


Les mods déclarent quels projets sont des exports orbitaux via .

À chaque , si le projet est enregistré,
              ses ressources collectées sont créditées dans .

À chaque , un log d'avertissement
              est émis — les ressources en attente ne sont pas créditées.


Usage :

            var service = new OrbitalStockService();
            service.RegisterExportProject("mission_arean_survey");
            // Brancher sur les events natifs (SpaceProjectEventPatchingService doit être actif) :
            EnhancedEventBus.Subscribe(SpecialProjectCompletedNativeEvent.Key, service.OnProjectCompleted);
            EnhancedEventBus.Subscribe(PortProjectCancelledNativeEvent.Key,    service.OnProjectCancelled);

Lie les paliers de réputation à des  du jeu.


Quand la réputation d'une entité change de palier, le binder active/désactive
ou met à jour des overrides enregistrés dans .



Override supporté confirmé dans le dump interop :

Faction.GetSpaceProjectResourceCostDivisor() — divise le coût des ressources
de projets spatiaux. Valeur 1.0 = pas d'effet, 2.0 = moitié prix, 0.5 = double prix.



Pour chaque entité mirrorée, un override distinct est enregistré avec la clé
Faction.GetSpaceProjectResourceCostDivisor_{entityId} afin d'éviter les conflits.


var binder = new ReputationEffectsBinder();
// Lier l'entité "corp_helios" à l'override de coût d'import
binder.BindEntity("corp_helios", new float[] { 0.5f, 0.75f, 1.0f, 1.5f, 2.0f });
// S'abonner aux changements :
EnhancedEventBus.Subscribe(ReputationChangedEvent.Key, binder.OnReputationChanged);

